import { useEffect, useMemo, useState } from "react";
import Navbar from "./components/Navbar";
import Hero from "./components/Hero";
import About from "./components/About";
import Skills from "./components/Skills";
import "./App.css";

const sectionIds = [
  "home",
  "about",
  "skills",
  "projects",
  "experience",
  "contact",
];

export default function App() {
  const [activeSection, setActiveSection] = useState("home");

  const observers = useMemo(() => {
    return sectionIds.reduce((acc, id) => {
      acc[id] = null;
      return acc;
    }, {});
  }, []);

  useEffect(() => {
    const options = {
      root: null,
      rootMargin: "0px",
      threshold: 0.6,
    };

    const handleIntersect = (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersect, options);
    sectionIds.forEach((id) => {
      const el = document.getElementById(id);
      if (el) {
        observer.observe(el);
      }
    });

    return () => {
      observer.disconnect();
    };
  }, [observers]);

  return (
    <div className="app-root">
      <Navbar activeSection={activeSection} />

      <main>
        <Hero />

        <About />

        <Skills />

        <section id="projects" className="section section-placeholder">
          <div className="container">
            <h2 className="section-title">Projects</h2>
            <p className="section-text">
              Showcase featured work and case studies here.
            </p>
          </div>
        </section>

        <section id="experience" className="section section-placeholder">
          <div className="container">
            <h2 className="section-title">Experience</h2>
            <p className="section-text">
              Share your professional timeline or highlights here.
            </p>
          </div>
        </section>

        <section id="contact" className="section section-placeholder">
          <div className="container">
            <h2 className="section-title">Contact</h2>
            <p className="section-text">
              Add your email, socials, or a contact form here.
            </p>
          </div>
        </section>
      </main>
    </div>
  );
}
